const msg = $input.first().json.message;
const chatId = msg.chat.id;
const text = msg.text || '';
const sd = $getWorkflowStaticData('global');
if (!sd.spend) sd.spend = { total_usd: 0, limit_usd: parseFloat('5.0' || '5'), anthropic_usd: 0, openai_usd: 0 };

if (text.startsWith('/setlimit')) {
  const val = parseFloat(text.split(' ')[1] || '');
  if (!isNaN(val) && val > 0) {
    sd.spend.limit_usd = val;
    return [{ json: { chatId, replyType: 'info', replyText: `вњ… Spend limit set to $${val.toFixed(2)}` } }];
  }
  return [{ json: { chatId, replyType: 'info', replyText: 'вќЊ Usage: /setlimit 10.0' } }];
}

if (text.startsWith('/resetspend')) {
  sd.spend.total_usd = 0; sd.spend.anthropic_usd = 0; sd.spend.openai_usd = 0;
  return [{ json: { chatId, replyType: 'info', replyText: 'вњ… Spend reset to $0.00' } }];
}

if (text.startsWith('/spend')) {
  const sp = sd.spend;
  const pct = Math.min(sp.total_usd / sp.limit_usd * 100, 100).toFixed(1);
  const filled = Math.floor(pct / 10);
  const bar = 'в–€'.repeat(filled) + 'в–‘'.repeat(10 - filled);
  return [{ json: { chatId, replyType: 'info', replyText: `рџ’° *Spend Report*\n${bar} ${pct}%\nTotal: $${sp.total_usd.toFixed(4)} / $${sp.limit_usd.toFixed(2)}\nAnthropic: $${sp.anthropic_usd.toFixed(4)}\nOpenAI: $${(sp.openai_usd || 0).toFixed(4)}` } }];
}

return [{ json: { chatId, text, replyType: 'menu' } }];

const cb = $input.first().json.callback_query;
const chatId = cb.message.chat.id;
const data = cb.data;
const callbackQueryId = cb.id;
const sd = $getWorkflowStaticData('global');
if (!sd.command_queue) sd.command_queue = [];

const enqueue = (cmd) => {
  if (sd.command_queue.length >= 50) sd.command_queue.shift();
  sd.command_queue.push(cmd);
};

let action = null, replyMenu = null;

if (data.startsWith('cmd:')) {
  const type = data.slice(4);
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type, payload: {} });
  action = 'queued';
} else if (data.startsWith('app:')) {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'launch-app', payload: { app: data.slice(4) } });
  action = 'queued';
} else if (data.startsWith('chrome:')) {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'chrome-profile', payload: { profile_directory: data.slice(7) } });
  action = 'queued';
} else if (data === 'menu:apps') { replyMenu = 'apps'; action = 'show_menu';
} else if (data === 'menu:chrome') {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'chrome-profiles-list', payload: {} });
  replyMenu = 'chrome'; action = 'show_menu';
} else if (data === 'menu:accounts') { replyMenu = 'accounts'; action = 'show_menu';
} else if (data === 'menu:terminal') { action = 'ask_terminal';
} else if (data === 'menu:install') { action = 'ask_install';
} else if (data.startsWith('account:')) {
  sd.active_account = parseInt(data.slice(8));
  action = 'account_switched';
}

return [{ json: { chatId, callbackQueryId, action, replyMenu, active_account: sd.active_account || 1 } }];

